 wt(AC/'recompute_qm28.py','''import csv,math\nfrom pathlib import Path\nR=Path(__file__).resolve().parents[1]\ndef rd(n):\n with (R/n).open() as f:return list(csv.DictReader(f))\na=rd('HT_PAIR_EFFECTS.csv')\nfor r in a:\n b=float(r['baseline_value']);t=float(r['treated_value']);assert abs(float(r['delta'])-(t-b))<1e-8;assert abs(float(r['lnRR'])-math.log(t/b))<1e-7\ni=next(x for x in rd('HT_REINFORCEMENT_INTERACTIONS.csv') if x['outcome']=='creep_rupture_time');assert abs(float(i['additive_interaction'])-5.7)<1e-9;assert abs(float(i['ratio_of_ratios'])-11.333333333333334)<1e-8\nprint({'pass':True,'pairs_checked':len(a)})''')
 wt(TS/'test_qm28.py','''import csv,json,unittest\nfrom pathlib import Path\nR=Path(__file__).resolve().parents[1]\nclass T(unittest.TestCase):\n def test_required(self):\n  q=['00_EXECUTIVE_VERDICT.md','INPUT_LEDGER.csv','ANALYSIS_COHORT.csv','PAIR_MATCHES.csv','EFFECT_ESTIMATES.csv','HIERARCHICAL_RESULTS.csv','DOSE_RESPONSE.csv','INTERACTION_EFFECTS.csv','HETEROGENEITY.csv','SENSITIVITY_ANALYSIS.csv','NULL_NEGATIVE_RESULTS.csv','CONFLICT_LEDGER.csv','PROVENANCE.jsonl','METHODS.md','LIMITATIONS.md','PLOT_SPECS.json','WEB_TO_LOCAL_REQUEST.json','LOCAL_ABSORPTION_PROMPT.md','WINDOW_STATUS.json','HEAT_TREATMENT_SEQUENCES.csv','HT_PAIR_EFFECTS.csv','HT_DOSE_RESPONSE.csv','HT_REINFORCEMENT_INTERACTIONS.csv'];self.assertTrue(all((R/x).exists() for x in q))\n def test_pairs(self):\n  a=list(csv.DictReader((R/'HT_PAIR_EFFECTS.csv').open()));self.assertEqual(len(a),30);[self.assertAlmostEqual(float(x['delta']),float(x['treated_value'])-float(x['baseline_value']),7) for x in a]\n def test_interaction(self):\n  a=list(csv.DictReader((R/'HT_REINFORCEMENT_INTERACTIONS.csv').open()));x=next(r for r in a if r['outcome']=='creep_rupture_time');self.assertAlmostEqual(float(x['additive_interaction']),5.7,7)\n def test_plots(self):\n  a=json.loads((R/'PLOT_SPECS.json').read_text());self.assertEqual(len(a['plots']),4);[self.assertTrue((R/x).exists()) for p in a['plots'] for x in p['outputs']]\n def test_no_nested_zip(self):self.assertEqual(list(R.rglob('*.zip')),[])\n def test_ceiling(self):\n  s=json.loads((R/'WINDOW_STATUS.json').read_text());self.assertLessEqual(s['claim_level_max'],2);self.assertEqual(s['status'],'CONTINUE_DATA_GAP')\n''')
 rr=subprocess.run([sys.executable,str(AC/'recompute_qm28.py')],cwd=PKG,capture_output=True,text=True,check=True); tt=subprocess.run([sys.executable,'-m','unittest','discover','-s',str(TS),'-v'],cwd=PKG,capture_output=True,text=True); wt(PKG/'self_test_output.txt',tt.stdout+'\n'+tt.stderr+f'\npass={str(tt.returncode==0).lower()}'); assert tt.returncode==0; wt(PKG/'RUN_LOG.txt',f'generated_at={NOW}\nsnapshot={SNAP}\n{rr.stdout.strip()}\nlogical_plots=4\nplot_files=12')
